#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>dp(max(2,n)+1);dp[1]=1;if(n>=2)dp[2]=2;for(int i=3;i<=n;i++)dp[i]=(dp[i-1]+dp[i-2])%10007;printf("%lld\n",dp[n]%10007);}
